mapper.select:
SELECT U.USER_EMAIL , GROUP_CONCAT(TU.TARGET_ID) AS target_id, GROUP_CONCAT(ap_no) AS ap_no, U.USER_NO AS service_user, U.USER_NAME, (SELECT TEAM_NAME FROM PI_GROUP G WHERE G.INSA_CODE=U.INSA_CODE) AS USER_GROUP FROM PI_TARGET_USER TU LEFT OUTER JOIN PI_USER U ON U.USER_EMAIL != ' ' AND U.USER_NO = TU.USER_NO WHERE U.USER_EMAIL IS NOT NULL AND U.USER_NO IS NOT NULL AND TU.TARGET_ID IN
#{item}
GROUP BY U.USER_NO

SELECT U.USER_NO, U.USER_EMAIL, IFNULL(U.SOSOK, '') AS SOSOK, DPG.NOTEPAD, U.USER_NAME, CONCAT(T.NAME, ' : ', DPG.DATA_PROCESSING_NAME) AS DETAIL_CON, #{comment} AS COMMENT FROM PI_USER U, PI_DATA_PROCESSING DP, PI_TARGETS T, PI_DATA_PROCESSING_GROUP DPG WHERE U.USER_NO = #{ok_user_no} AND T.TARGET_ID = DP.TARGET_ID AND T.TARGET_ID = DPG.TARGET_ID AND T.AP_NO = DP.AP_NO AND DPG.IDX IN
#{item}
GROUP BY DETAIL_CON

mapper.update:
UPDATE PI_TEMPLATE
SET NAME = #{name}, CON = #{template_con}
WHERE IDX = #{idx}
AND FLAG = 'Y'
AND FLAG_CON LIKE 'sendmail_%'

