SELECT U.USER_EMAIL, U.USER_NO AS SERVICE_USER, U.USER_NAME, (SELECT TEAM_NAME FROM PI_GROUP G WHERE G.INSA_CODE = U.INSA_CODE) AS USER_GROUP, GROUP_CONCAT(TU.TARGET_ID) AS TARGET_ID, GROUP_CONCAT(TU.AP_NO) AS AP_NO FROM PI_TARGET_USER TU LEFT OUTER JOIN PI_USER U ON U.USER_EMAIL != ' ' AND U.USER_NO = TU.USER_NO WHERE U.USER_EMAIL IS NOT NULL AND U.USER_NO IS NOT NULL AND TU.TARGET_ID IN
#{item}
GROUP BY U.USER_NO
